// Helper sample image data URL (SVG rendered as base64 avatar placeholder with badge)
const createSamplePhoto = (name: string, role: string, kab: string) => {
  const canvas = document.createElement('canvas');
  canvas.width = 400;
  canvas.height = 400;
  const ctx = canvas.getContext('2d');
  if (ctx) {
    // Background gradient
    const grad = ctx.createLinearGradient(0, 0, 400, 400);
    grad.addColorStop(0, '#1e293b');
    grad.addColorStop(1, '#0f172a');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, 400, 400);

    // Header badge
    ctx.fillStyle = '#dc2626';
    ctx.fillRect(0, 0, 400, 40);
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 16px sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('BAWASLU PROVINSI RIAU - PRESENSI DARING', 200, 26);

    // Avatar Circle
    ctx.beginPath();
    ctx.arc(200, 160, 65, 0, Math.PI * 2);
    ctx.fillStyle = '#d97706';
    ctx.fill();

    // Initial
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 42px sans-serif';
    ctx.fillText(name.split(' ').map(n => n[0]).slice(0, 2).join(''), 200, 175);

    // Name & Details
    ctx.font = 'bold 18px sans-serif';
    ctx.fillText(name, 200, 260);

    ctx.fillStyle = '#94a3b8';
    ctx.font = '14px sans-serif';
    ctx.fillText(`${role} - ${kab}`, 200, 285);

    // Watermark Footer
    ctx.fillStyle = 'rgba(0,0,0,0.7)';
    ctx.fillRect(0, 320, 400, 80);
    ctx.fillStyle = '#22c55e';
    ctx.font = 'bold 12px monospace';
    ctx.textAlign = 'left';
    ctx.fillText(`✓ PRESENSI REAL-TIME VERIFIED`, 15, 345);
    ctx.fillStyle = '#f8fafc';
    ctx.font = '11px monospace';
    ctx.fillText(`Waktu: 21 Jul 2026, 09:14:22 WIB`, 15, 365);
    ctx.fillText(`Lokasi: ${kab}, Riau (GPS OK)`, 15, 385);
  }
  return canvas.toDataURL('image/jpeg', 0.8);
};

