// Helper function to get list of participant names based on selected kabKota
export function getPesertaByKabKota(kabKota: string): string[] {
  return DATA_PESERTA_BY_KABKOTA[kabKota] || [];
}

// Get all names across all regions
export function getAllPesertaNames(): string[] {
  const allNames: string[] = [];
  Object.values(DATA_PESERTA_BY_KABKOTA).forEach(list => {
    list.forEach(name => {
      if (!allNames.includes(name)) {
        allNames.push(name);
      }
    });
  });
  return allNames.sort();
}
